ProductLimitConfig = {}
ProductLimitConfig.Online = 1
ProductLimitConfig.Offline = 2
ProductLimitConfig.Transfer = 3
ProductLimitConfig.products = {}

function ProductLimitConfig:init(config)
    self:initProduct(config)
end

function ProductLimitConfig:initProduct(config)
    for i, v in pairs(config) do
        local item = {}
        item.id = tonumber(v.id)
        item.itemId = tonumber(v.itemId)
        item.max_num = tonumber(v.max_num)
        self.products[item.id] = item
    end
    table.sort(self.products, function ( a, b )
        return a.id < b.id
    end)
end

function ProductLimitConfig:getLimitNum(itemId)
    for i, v in pairs(self.products) do
        if v.itemId == itemId then
            return v.max_num
        end
    end
    return 99999
end



return ProductLimitConfig